	@Test
	void generatedNameFilterRewritePreservesRowsAndUsesBoundObjectLookup(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSyntheticEngineeringAssemblies(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				String filterQuery = engineeringAssemblyNameFilterQuery();
				String valuesQuery = engineeringAssemblyNameValuesQuery();
				long filterRows = countRows(connection, filterQuery);
				long valuesRows = countRows(connection, valuesQuery);
				assertEquals(ASSEMBLY_COUNT, filterRows,
						"The generated FILTER query should return the selected assemblies");
				assertEquals(valuesRows, filterRows,
						"The finite FILTER rewrite must preserve the rows produced by the equivalent VALUES query");

				Explanation explanation = connection.prepareTupleQuery(filterQuery)
						.explain(Explanation.Level.Optimized);
				StatementPattern namePattern = findStatementPattern((TupleExpr) explanation.tupleExpr(), ENG_NAME,
						"assemblyName");
				assertTrue(namePattern != null,
						"Expected the optimized FILTER query to retain the generated name lookup. plan="
								+ explanation);

				double plannedAccessRows = namePattern.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_ACCESS_ROWS);
				assertEquals("directLookup",
						namePattern.getStringMetricPlanned(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE),
						"A finite generated literal domain should use direct index lookup instead of a predicate scan. "
								+ "metrics=" + namePattern);
				assertEquals("[P, O]",
						namePattern.getStringMetricPlanned(TelemetryMetricNames.PLANNED_LOOKUP_COMPONENTS),
						"A finite generated literal domain should bind predicate and object for the name lookup. "
								+ "metrics=" + namePattern);
				assertTrue(Double.isFinite(plannedAccessRows) && plannedAccessRows > 0.0d
						&& plannedAccessRows <= ASSEMBLY_COUNT * 2.0d,
						"The generated FILTER rewrite should keep planned access near the selected object literals. "
								+ "plannedAccessRows=" + plannedAccessRows + ", metrics=" + namePattern);
			}
		} finally {
			repository.shutDown();
		}
	}

	private static void loadSyntheticEngineeringAssemblies(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 1; i <= ASSEMBLY_COUNT; i++) {
				Resource assembly = assembly(i);
				connection.add(assembly, ENG_NAME, VF.createLiteral("Assembly " + i));
				connection.add(assembly, RDF_TYPE, ENG_ASSEMBLY);
				for (int componentIndex = 0; componentIndex < COMPONENTS_PER_ASSEMBLY; componentIndex++) {
					connection.add(VF.createIRI("urn:test:engineering:component:" + i + ":" + componentIndex),
							ENG_PART_OF, assembly);
				}
			}
			for (int i = 0; i < 2_000; i++) {
				Resource assembly = VF.createIRI("urn:test:engineering:noise-assembly:" + i);
				connection.add(assembly, ENG_NAME, VF.createLiteral("Noise Assembly " + i));
				connection.add(assembly, RDF_TYPE, ENG_ASSEMBLY);
			}
			connection.commit();
		}
	}

	private static void loadSyntheticMedicalObservations(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			int[] selectedValues = { 50, 60, 70 };
			for (int value : selectedValues) {
				for (int i = 0; i < OBSERVATIONS_PER_VALUE; i++) {
					Resource observation = VF.createIRI("urn:test:medical:observation:" + value + ":" + i);
					Resource encounter = VF.createIRI("urn:test:medical:encounter:" + value + ":" + i);
					connection.add(observation, MED_VALUE, VF.createLiteral(String.valueOf(value), XSD.INTEGER));
					connection.add(encounter, MED_HAS_OBSERVATION, observation);
				}
			}
			for (int i = 0; i < 2_000; i++) {
				Resource observation = VF.createIRI("urn:test:medical:noise-observation:" + i);
				connection.add(observation, MED_VALUE, VF.createLiteral(String.valueOf(1_000 + i), XSD.INTEGER));
			}
			connection.commit();
		}
	}

	private static void loadSyntheticLibraryBranches(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			Resource branch0 = VF.createIRI("urn:test:library:branch:0");
			Resource branch1 = VF.createIRI("urn:test:library:branch:1");
			connection.add(branch0, LIB_NAME, VF.createLiteral("Branch 0"));
			connection.add(branch1, LIB_NAME, VF.createLiteral("Branch 1"));
			for (int i = 0; i < COPIES_PER_SELECTED_LIBRARY_BRANCH; i++) {
				Resource branch0Copy = VF.createIRI("urn:test:library:copy:0:" + i);
				Resource branch1Copy = VF.createIRI("urn:test:library:copy:1:" + i);
				connection.add(branch0Copy, LIB_LOCATED_AT, branch0);
				connection.add(branch0Copy, RDF_TYPE, LIB_COPY);
				connection.add(branch1Copy, LIB_LOCATED_AT, branch1);
				connection.add(branch1Copy, RDF_TYPE, LIB_COPY);
			}
			for (int i = 0; i < LIBRARY_NOISE_BRANCH_COUNT; i++) {
				connection.add(VF.createIRI("urn:test:library:noise-branch:" + i), LIB_NAME,
						VF.createLiteral("Common Branch"));
			}
			connection.commit();
		}
	}

	private static Resource assembly(int index) {
		return VF.createIRI("urn:test:engineering:assembly:" + index);
	}

	private static BindingSetAssignment assemblyNameBindings() {
		BindingSetAssignment assignment = new BindingSetAssignment();
		List<BindingSet> bindingSets = new ArrayList<>();
		for (int i = 1; i <= ASSEMBLY_COUNT; i++) {
			QueryBindingSet bindingSet = new QueryBindingSet();
			bindingSet.addBinding("assemblyName", VF.createLiteral("Assembly " + i));
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

	private static void assertDirectFiniteDerivedPartOfSurface(LmdbStore store, BindingSetAssignment assemblyNames,
			StatementPattern name, StatementPattern type, StatementPattern partOf) {
		JoinFactorCostModel costModel = (JoinFactorCostModel) store.getBackingStore().getEvaluationStatistics();
		Optional<JoinFactorCostModel.FactorCostEstimate> estimate = costModel.estimateFactorCost(partOf,
				JoinFactorCostModel.CostContext.of(Set.of("assemblyName", "assembly"), 3.0d, 3.0d, true, true,
						Map.of("assemblyName", Set.of(VF.createLiteral("Assembly 1"),
								VF.createLiteral("Assembly 2"), VF.createLiteral("Assembly 3"))),
						List.of(assemblyNames, name, type)));
		assertTrue(estimate.isPresent(), "Expected a direct cost-model estimate for the derived partOf surface");
		assertEquals(COMPONENTS_PER_ASSEMBLY,
				estimate.get().getDoubleMetrics().get(TelemetryMetricNames.PLANNED_ACCESS_ROWS),
				COMPONENTS_PER_ASSEMBLY * 0.25d,
				"The direct cost-model path should use the per-assembly partOf access path. metrics="
						+ estimate.get().getStringMetrics() + estimate.get().getDoubleMetrics());
		assertEquals(ASSEMBLY_COUNT, estimate.get().getDoubleMetrics().get("plannedRepeatedInvocations"), 0.0d,
				"The direct cost-model path should account for each finite assembly lookup. metrics="
						+ estimate.get().getStringMetrics() + estimate.get().getDoubleMetrics());
		assertEquals(ASSEMBLY_COUNT * COMPONENTS_PER_ASSEMBLY,
				estimate.get().getDoubleMetrics().get(TelemetryMetricNames.PLANNED_WORK_ROWS),
				COMPONENTS_PER_ASSEMBLY * 0.25d,
				"The direct cost-model path should keep total work near the finite partOf surface. metrics="
						+ estimate.get().getStringMetrics() + estimate.get().getDoubleMetrics());
	}

	private static void assertFiniteDerivedLibraryFanout(JoinFactorCostModel costModel,
			EvaluationStatistics statistics, TupleExpr join, JoinFactorCostModel.EstimationTier tier) {
		LmdbCascadesConnectedJoinPlanner.Plan plan = LmdbCascadesConnectedJoinPlanner
				.plan(join, Set.of(), costModel, statistics, tier)
				.orElseThrow();
		StatementPattern plannedLocatedAt = findStatementPattern(plan.tupleExpr(), LIB_LOCATED_AT, "branch");
		assertTrue(plannedLocatedAt != null, "Expected planned locatedAt lookup. plan=" + plan.tupleExpr());

		double expectedRows = 2.0d * COPIES_PER_SELECTED_LIBRARY_BRANCH;
		double plannedRows = plannedLocatedAt.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS);
		assertTrue(plannedRows >= expectedRows * 0.75d,
				"The connected Cascades planner should keep the finite-derived fanout when finite names derive "
						+ "high-fanout branches. tier=" + tier + ", plannedRows=" + plannedRows + ", expectedRows="
						+ expectedRows + ", metrics=" + plannedLocatedAt);
	}

